      out[k] = safeJSON(r, { _raw: r });
    } catch (e) {
      out[k] = { _error: e.message };
    }
  }
  // AC-3 hover: hover then re-capture tab + cta
  try {
    const tab = await page.$('ul.header-nav li a, [class*="subnav"] li a');
    if (tab) await tab.hover();
